    pub fn accept_task(&self, task: &str) -> RunEnvelope {
        RunEnvelope {
            run_id: gen_id("run"),
            task: task.to_string(),
            status: RunStatus::Pending,
            risk_score: 0.0,
            verified_payload: None,
            evidence_packet: EvidencePacket::new(),
            created_at: now(),
        }
    }

