#![warn(missing_docs)]

use serde::{Deserialize, Serialize};
use std::collections::HashMap;

/// Integration coordinator
#[derive(Clone, Debug, Serialize, Deserialize)]
pub struct IntegrationMessage {
    /// Source system
    pub source: String,
    /// Destination system
    pub destination: String,
    /// Message type
    pub message_type: String,
    /// Message payload
    pub payload: serde_json::Value,
    /// Timestamp
    pub timestamp: f64,
}

/// gAIng coordination service
#[derive(Clone, Debug)]
pub struct Service {
    message_queue: Vec<IntegrationMessage>,
    system_registry: HashMap<String, SystemStatus>,
}

/// Status of an integrated system
#[derive(Clone, Debug, Serialize, Deserialize)]
pub struct SystemStatus {
    /// System name
    pub name: String,
    /// Is system healthy
    pub healthy: bool,
    /// Last heartbeat
    pub last_heartbeat: f64,
    /// Message count
    pub message_count: u64,
}

impl Service {
    /// Create new integration service
    pub fn new() -> Self {
        Service {
            message_queue: Vec::new(),
            system_registry: HashMap::new(),
        }
